export type PublicListing = {
  externalId: string
  address: string
  city: string
  state: string
  zip: string
  price: number
  beds: number
  baths: number
  status: string
  sqft: number
  updatedAt: string
}

export function normalizeListing(raw: any): PublicListing {
  return {
    externalId: raw.id,
    address: raw.address,
    city: raw.city,
    state: raw.state,
    zip: raw.zip,
    price: raw.price,
    beds: raw.beds,
    baths: raw.baths,
    sqft: raw.sqft,
    status: raw.status ?? "UNKNOWN",
    updatedAt: raw.updated_at,
  }
}
