import fs from "fs"
import path from "path"

export function exportEvaluations(results: any[]) {
  const filePath = path.join(
    process.cwd(),
    "data",
    "evaluation-results.json"
  )

  fs.writeFileSync(
    filePath,
    JSON.stringify(
      {
        evaluatedAt: new Date().toISOString(),
        results,
      },
      null,
      2
    )
  )
}
