import fs from "fs"
import path from "path"

export function saveRawPayload(payload: any) {
  const filePath = path.join(process.cwd(), "data", "raw-public-payload.json")

  fs.writeFileSync(
    filePath,
    JSON.stringify(
      {
        fetchedAt: new Date().toISOString(),
        sample: payload.slice(0, 3), // only a few records
      },
      null,
      2
    )
  )
}
