export async function fetchFromPublicSource() {
  const controller = new AbortController()
  const timeout = setTimeout(() => controller.abort(), 8000)

  try {
    const res = await fetch(
      "https://jsonplaceholder.typicode.com/posts",
      { signal: controller.signal }
    )

    if (!res.ok) {
      throw new Error(`Fetch failed: ${res.status}`)
    }

    const raw = await res.json()

    console.log("RAW PUBLIC PAYLOAD SAMPLE:", raw[0])

    // Normalize to internal listing format
    return raw.slice(0, 10).map((item: any, index: number) => ({
      externalId: `PUBLIC_${item.id}`,
      address: item.title,
      city: "Dallas",
      state: "TX",
      zip: "75000",
      price: 250000 + index * 10000,
      beds: 3,
      baths: 2,
      sqft: 1600 + index * 100,
      updatedAt: new Date().toISOString(),
    }))

  } catch (err) {
    console.error("Public source fetch failed:", err)
    return []
  } finally {
    clearTimeout(timeout)
  }
}
